"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[465],{5454:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"3.6.0","metadata":{"permalink":"/release-notes/3.6.0","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2024-01-09-3.6.0.mdx","source":"@site/release-notes/2024-01-09-3.6.0.mdx","title":"Swipload 3.6.0 release notes","description":"This release simplifies creation and editing of freight orders, removes the Confirm details step, and increases performance.","date":"2024-01-09T00:00:00.000Z","formattedDate":"January 9, 2024","tags":[{"label":"shipper","permalink":"/release-notes/tags/shipper"},{"label":"shipment","permalink":"/release-notes/tags/shipment"},{"label":"freight","permalink":"/release-notes/tags/freight"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"3.6.0","title":"Swipload 3.6.0 release notes","description":"This release simplifies creation and editing of freight orders, removes the Confirm details step, and increases performance.","tags":["shipper","shipment","freight"]},"unlisted":false,"nextItem":{"title":"Swipload 3.5.0 release notes","permalink":"/release-notes/3.5.0"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Shipments\\n\\n### Features\\n\\n#### Skip the \\"Confirm details\\" step on freight orders when sending a shipment to a carrier\\n\\nWith all details already in place with the [redesigned create / edit freight order page](#redesigned-create-/-edit-freight-order-page), this step can be skipped after sending to carrier. #2704\\n\\n#### More customisable shipments list\\n\\nShipmentRef, SwipRef and freight order status are now optional columns in the shipments table list view. #2948\\n\\n### Fixes\\n\\n- minor UI design improvements on shipments.\\n\\n## Freight orders\\n\\n### Features\\n\\n#### Drag n\' drop photos and attachments onto a freight order\\n\\nPreviously you had to click the upload button when creating or editing a freight order, now you can instead drop the #2959\\n\\n### Changes\\n\\n#### Redesigned create / edit freight order page\\n\\nAdds pickup and delivery details to the create and edit form. This includes contact details and information to driver that is also visible on the POD. #2257\\n\\n## Performance improvements\\n\\n- browsing pages after initial load is faster. #2893\\n\\n\x3c!--truncate--\x3e\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"3.5.0","metadata":{"permalink":"/release-notes/3.5.0","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-12-22-3.5.0.mdx","source":"@site/release-notes/2023-12-22-3.5.0.mdx","title":"Swipload 3.5.0 release notes","description":"Freight orders","date":"2023-12-22T00:00:00.000Z","formattedDate":"December 22, 2023","tags":[{"label":"shipper","permalink":"/release-notes/tags/shipper"},{"label":"api","permalink":"/release-notes/tags/api"},{"label":"freight","permalink":"/release-notes/tags/freight"},{"label":"fixes","permalink":"/release-notes/tags/fixes"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"3.5.0","title":"Swipload 3.5.0 release notes","tags":["shipper","api","freight","fixes"]},"unlisted":false,"prevItem":{"title":"Swipload 3.6.0 release notes","permalink":"/release-notes/3.6.0"},"nextItem":{"title":"Swipload 3.4.0 release notes","permalink":"/release-notes/3.4.0"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Freight orders\\n\\n### Features\\n\\n#### Consignor & Consignee reference available in /freight (API) endpoint as input from external systems. #2956\\n\\n### Fixes\\n\\n- Showing actual pickup and delivery date/time on the POD. #2996\\n- Cancelling a freight order in some cases showed something went wrong though it didn\'t. #2946\\n- Formatting of shipment total weight in some rare cases. #3043\\n\\n## Billing\\n\\n### Features\\n\\n#### Weekly billing of delivered shipment. #3022\\n\\n\x3c!--truncate--\x3e\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"3.4.0","metadata":{"permalink":"/release-notes/3.4.0","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-12-13-3.4.0.mdx","source":"@site/release-notes/2023-12-13-3.4.0.mdx","title":"Swipload 3.4.0 release notes","description":"This release add new features for shippers and carriers and fixes several issues in the UI .","date":"2023-12-13T00:00:00.000Z","formattedDate":"December 13, 2023","tags":[{"label":"shipper","permalink":"/release-notes/tags/shipper"},{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"shipment","permalink":"/release-notes/tags/shipment"},{"label":"freight","permalink":"/release-notes/tags/freight"},{"label":"fixes","permalink":"/release-notes/tags/fixes"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"3.4.0","title":"Swipload 3.4.0 release notes","description":"This release add new features for shippers and carriers and fixes several issues in the UI .","tags":["shipper","carrier","shipment","freight","fixes"]},"unlisted":false,"prevItem":{"title":"Swipload 3.5.0 release notes","permalink":"/release-notes/3.5.0"},"nextItem":{"title":"Swipload 3.3.0 release notes","permalink":"/release-notes/3.3.0"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Shipments\\n\\n### Features\\n\\n#### Shippers can now set \\"Base price + expenses\\" as a default price format for a Carrier #3007\\n\\n#### Agreements will now also affect Shipment\\n\\nMost importantly, Shippers will now be able to edit Freights that are a part of Shipments according to the existing agreement rule that allows changes to be made until given status. #3033\\n\\n#### Carriers now see new price type \\"Base price + expenses\\" when filtering their Shipment lists #2990\\n\\n#### Will be easier for Shipper to compare prices of different freights\\n\\nWe now display price / kg on the Shipment page. #2962\\n\\n### Changes\\n\\n#### Phone number prefix no longer based on IP-address\\n\\nNo longer show a user an incorrect flag icon / prefix when inputting phone numbers, as these were based on VPN / ISPs IP-address #2942\\n\\n#### More information when a price is changed\\n\\nShipment log will now show what price was changed from and to. #2953\\n\\n#### Easier to see which Freight orders have deviations from the POD-list #2973\\n\\n#### Shippers now prompted if they really want to send a Shipment with the default price format #3004\\n\\n### Fixes\\n\\n- Shippers can clearly see where/how to edit the price of a shipment. #2930\\n- User can no longer open multiple context menus #2858\\n- Deviation icon no longer covers up other icons on freight ribbons #2931\\n- Anonymous users will now see status of freights updated upon signing #3012\\n- Stop showing zeroes (\\"0\\") when shipper hasn\'t input a value for freight dimensions (for example weight or LDM) #3017\\n- No longer presented with the option to remove a freight from its original shipment #3019\\n- Freight shippers now get same context menu options as Shipment shippers #2875\\n\\n\x3c!--truncate--\x3e\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"3.3.0","metadata":{"permalink":"/release-notes/3.3.0","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-12-03-3.3.0.mdx","source":"@site/release-notes/2023-12-03-3.3.0.mdx","title":"Swipload 3.3.0 release notes","description":"This release implements new pricing model for shipments, carriers vehicle reference, consignee in addition to several fixes.","date":"2023-12-03T00:00:00.000Z","formattedDate":"December 3, 2023","tags":[{"label":"shipper","permalink":"/release-notes/tags/shipper"},{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"shipment","permalink":"/release-notes/tags/shipment"},{"label":"freight","permalink":"/release-notes/tags/freight"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"3.3.0","title":"Swipload 3.3.0 release notes","description":"This release implements new pricing model for shipments, carriers vehicle reference, consignee in addition to several fixes.","tags":["shipper","carrier","shipment","freight"]},"unlisted":false,"prevItem":{"title":"Swipload 3.4.0 release notes","permalink":"/release-notes/3.4.0"},"nextItem":{"title":"Swipload 3.0.0 release notes","permalink":"/release-notes/3.0.0"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Shipments\\n\\n### Features\\n\\n#### New pricing model for shipments: base price + expenses\\n\\nWith this you as the shipper can set a base price for the whole shipment and the carrier may add surcharges after delivery. This is typically used when an agreement exists between you as the shipper and your carrier. #2969\\n\\n#### Carriers vehicle reference on shipments\\n\\nAs carrier you can specify your vehicle number/reference on assigned shipments. This is shown to the shipper and can be used for multiple properties, like display on Bill of Laden and reports. #2958\\n\\n#### Add new freight order directly on shipment\\n\\nIn addition to merging and moving around existing freight orders on a shipment, you can now also create and add a new freight order to an existing shipment in Draft status. #2961\\n\\n### Fixes\\n\\n- confusing scrolling when opening a shipment. #2992\\n- attachments and pictures for freight orders shown on shipment for carrier. #3000\\n\\n## Freight orders\\n\\n### Features\\n\\n#### Consignee details\\n\\nIn addition to delivery location you may now specify the final [consignee](https://en.wikipedia.org/wiki/Consignee), your end-customer, on a freight order. Customise shipment list columns to add the consignee column and filter shipments on consignee. The consignee is displayed on the POD. #2959\\n\\n#### Load quantity\\n\\nYou may now specify a total quantity, (i.e. number of boxes) in addition to weight, loading metre (LDM), volume, pallets and dimension on a freight order. #2901\\n\\n### Changes\\n\\n#### Simplify address input/updates (even simpler than before!)\\n\\nLooking up a business name and location is super easy when creating a freight order, but modifying the address could be a challenge. We\'ve now made it easy to manually change the pickup, delivery, and consignee address. #2262\\n\\n### Fixes\\n\\n- error sending new freight order that happened when navigating back and forth. #2900\\n- requirements not always shown on Draft freight order. #2913\\n- POD status not always updated for drivers. #2947\\n\\n\x3c!--truncate--\x3e\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"3.0.0","metadata":{"permalink":"/release-notes/3.0.0","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-11-05-3.0.0.mdx","source":"@site/release-notes/2023-11-05-3.0.0.mdx","title":"Swipload 3.0.0 release notes","description":"Features","date":"2023-11-05T00:00:00.000Z","formattedDate":"November 5, 2023","tags":[{"label":"shipper","permalink":"/release-notes/tags/shipper"},{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"shipment","permalink":"/release-notes/tags/shipment"},{"label":"driver","permalink":"/release-notes/tags/driver"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"3.0.0","title":"Swipload 3.0.0 release notes","tags":["shipper","carrier","shipment","driver"]},"unlisted":false,"prevItem":{"title":"Swipload 3.3.0 release notes","permalink":"/release-notes/3.3.0"},"nextItem":{"title":"Swipload 2.51.2 release notes","permalink":"/release-notes/2.51.2"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Features\\n\\n### Shipments\\n\\nCreate, communicate, negotiate and get one price for multiple freight orders using a single Shipment. Order a FTL or LTL by combining multiple freight orders. A shipment can have a single or multiple pickup points and a single or multiple delivery points, and enables individual PODs for different end customers on a single shipment.\\n\\nShipments support the same features as regular freight orders, like:\\n\\n- Request quote from one or many carriers\\n- Send to carrier as fixed price shipment\\n- Send to carrier as time & material pricing\\n- Communicate with carriers and drivers on a shipment\\n- Share to spot market for instant resolving of your shipment need\\n- Agreements, with multiple terms for your current carrier(s)\\n- Integrations with ERPs and TMSs\\n\\nand much much more.\\n\\n### Photo documentation\\n\\nWhen signing for pickup and/or delivery you may now attach one or more photos documenting the pickup or delivery. Photos are visible for the shipper and can be presented to the end customer.\\n\\n### Deviation handling\\n\\nIf a deviation occurs during the delivery process, you may now report it immediately, i.e. when signing for pickup or delivery. Attach photos to deviations for adding additional context and documentation.\\n\\n\x3c!--truncate--\x3e\\n\\n## Bug fixes\\n\\nNone\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"2.51.2","metadata":{"permalink":"/release-notes/2.51.2","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-09-21-2.51.2.mdx","source":"@site/release-notes/2023-09-21-2.51.2.mdx","title":"Swipload 2.51.2 release notes","description":"Hotfix release for freight order settlements","date":"2023-09-21T00:00:00.000Z","formattedDate":"September 21, 2023","tags":[{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"driver","permalink":"/release-notes/tags/driver"}],"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"2.51.2","title":"Swipload 2.51.2 release notes","description":"Hotfix release for freight order settlements","tags":["carrier","driver"]},"unlisted":false,"prevItem":{"title":"Swipload 3.0.0 release notes","permalink":"/release-notes/3.0.0"},"nextItem":{"title":"Swipload 2.51 release notes","permalink":"/release-notes/2.51"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n## Bug fixes\\n\\n- #2687 Issue creating final settlement for delivered freight order\\n- #2689 Issue for driver to add comment when signing for delivered\\n\\n\x3c!--truncate--\x3e\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"},{"id":"2.51","metadata":{"permalink":"/release-notes/2.51","editUrl":"https://github.com/swipload/docs/tree/main/release-notes/2023-09-19-2.51.mdx","source":"@site/release-notes/2023-09-19-2.51.mdx","title":"Swipload 2.51 release notes","description":"This release focuses on multiple language support, handling localisation in UI, PODs, notifications, SMS\'es and emails in regards to users or receivers language. To update your language setting go to your profile settings.","date":"2023-09-19T00:00:00.000Z","formattedDate":"September 19, 2023","tags":[{"label":"carrier","permalink":"/release-notes/tags/carrier"},{"label":"i18n","permalink":"/release-notes/tags/i-18-n"},{"label":"shipper","permalink":"/release-notes/tags/shipper"}],"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"2.51","title":"Swipload 2.51 release notes","tags":["carrier","i18n","shipper"]},"unlisted":false,"prevItem":{"title":"Swipload 2.51.2 release notes","permalink":"/release-notes/2.51.2"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\nThis release focuses on multiple language support, handling localisation in UI, PODs, notifications, SMS\'es and emails in regards to users or receivers language. To update your language setting go to your [profile settings](https://app.swipload.no/settings/your-profile).\\n\\n## Features\\n\\n### Language support\\n\\n- #2409 As a User I can choose English or Norwegian language in my profile settings, to change the literal language in the application\\n- #2630 As a User my application is correctly rendered with the language tied to my user profile\\n- #2625 As an Administrator and Invitee I can assign default language when [creating a User](https://app.swipload.no/settings/swipload-users)\\n\\n### Freights\\n\\n- #1713 As a Shipper I can see \\"Sent to\\" and \\"Opened by\\" also for my colleagues\' shipments\\n\\n## Bug fixes\\n\\n- #2353 Lost details on the waybill (consignment note) for settlement freights\\n- #2052 Carrier details does not appear in the consignment note on for settlement or fixed price (freight requests) freight orders\\n- #2626 \'Send freight order\' button in freight-card modal is inactive, and can not be clicked\\n- #2627 On \'send-to-carrier\' page, the carrier cards are misaligned\\n- #2668 Cannot make Settlement report in for certain companies\\n\\n## RSS Feed\\n\\nSubscribe to all our release notes via RSS. The feeds can be found at:\\n\\n<Tabs>\\n<TabItem value=\\"RSS\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/rss.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"Atom\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/atom.xml\\n```\\n\\n</TabItem>\\n<TabItem value=\\"JSON\\">\\n\\n```text\\nhttps://docs.swipload.com/release-notes/feed.json\\n```\\n\\n</TabItem>\\n</Tabs>"}]}')}}]);